/**
 * E2e tests for category: edge-cases
 * Generated by html-to-markdown-e2e-generator — do not edit manually.
 */
import { describe, it, expect } from 'vitest';
import { convert } from '@kreuzberg/html-to-markdown';

describe('edge-cases', () => {
  it('empty_html: Empty HTML document', () => {
    const html = `<html><head></head><body></body></html>`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content.trim()).toBe('');
  });

  it('encoding_cjk_characters: CJK (Chinese, Japanese, Korean) characters are preserved', () => {
    const html = `<p>中文内容</p><p>日本語テキスト</p><p>한국어 텍스트</p>`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content.trim().length).toBeGreaterThan(0);
    expect(content).toContain('中文内容');
    expect(content).toContain('日本語テキスト');
    expect(content).toContain('한국어 텍스트');
  });

  it('encoding_html_entities: Common HTML entities are decoded in output', () => {
    const html = `<p>&amp; &lt; &gt; &nbsp; &quot; &apos;</p>`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content.trim().length).toBeGreaterThan(0);
    expect(content).toContain('&');
    expect(content).toContain('<');
    expect(content).toContain('>');
  });

  it('encoding_named_entities: Named HTML entities like &mdash; and &hellip; are decoded', () => {
    const html = `<p>Em dash&mdash;used for parenthetical remarks&mdash;is common. Ellipsis&hellip; indicates omission. Non-breaking&nbsp;space.</p>`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content.trim().length).toBeGreaterThan(0);
    expect(content).toContain('—');
    expect(content).toContain('…');
  });

  it('encoding_numeric_entities: Numeric HTML entities (decimal and hex) are decoded', () => {
    const html = `<p>Copyright: &#169; Trade: &#174; Euro: &#8364; Hex: &#x00A9;</p>`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content.trim().length).toBeGreaterThan(0);
    expect(content).toContain('©');
    expect(content).toContain('®');
    expect(content).toContain('€');
  });

  it('encoding_unicode_emoji: Emoji and Unicode characters are preserved', () => {
    const html = `<p>Hello 🌍 World 🚀</p><p>Stars: ⭐ ✨</p>`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content.trim().length).toBeGreaterThan(0);
    expect(content).toContain('🌍');
    expect(content).toContain('🚀');
    expect(content).toContain('⭐');
  });

  it('html_comments_only: Document containing only HTML comments produces empty output', () => {
    const html = `<!-- This is a comment --><!-- Another comment -->`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content.trim()).toBe('');
  });

  it('just_whitespace_input: Input that is only whitespace characters (spaces, tabs, newlines) produces empty output', () => {
    const html = `   `;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content.trim()).toBe('');
  });

  it('malformed_deeply_nested_elements: Deeply nested elements (100 levels) are handled without stack overflow', () => {
    const html = `<div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><p>Deeply nested content</p></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div>`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content.trim().length).toBeGreaterThan(0);
    expect(content).toContain('Deeply nested content');
  });

  it('malformed_missing_block_closing_tags: Missing closing tags on block elements are auto-closed by parser', () => {
    const html = `<div><h1>Title<p>First paragraph<p>Second paragraph</div>`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content.trim().length).toBeGreaterThan(0);
    expect(content).toContain('Title');
    expect(content).toContain('First paragraph');
    expect(content).toContain('Second paragraph');
  });

  it('malformed_overlapping_tags: Overlapping bold/italic tags are recovered by the HTML parser without panic', () => {
    const html = `<p><b><i>bold and italic</b></i></p>`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content.trim().length).toBeGreaterThan(0);
    expect(content).toContain('bold and italic');
  });

  it('malformed_unclosed_paragraph: Unclosed <p> tag is recovered gracefully and content is preserved', () => {
    const html = `<p>This paragraph is never closed`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content.trim().length).toBeGreaterThan(0);
    expect(content).toContain('This paragraph is never closed');
  });

  it('script_tags_only: Document with only script tags produces empty output (scripts are stripped)', () => {
    const html = `<html><head><script>alert('xss')</script></head><body><script>document.write('hello')</script></body></html>`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content.trim()).toBe('');
  });

  it('style_tags_only: Document with only style tags produces empty output (styles are stripped)', () => {
    const html = `<html><head><style>body { color: red; }</style></head><body><style>.foo { margin: 0; }</style></body></html>`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content.trim()).toBe('');
  });

  it('whitespace_only: Whitespace-only content', () => {
    const html = `<p>   </p>`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content.trim()).toBe('');
  });

  it('xss_javascript_url_blocked: javascript: URLs in href attributes are preserved in link output (no URL scheme filtering is applied)', () => {
    const html = `<p><a href="javascript:alert('xss')">Click me</a></p>`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content.trim().length).toBeGreaterThan(0);
    expect(content).toContain('Click me');
  });

  it('xss_onclick_handler_removed: onclick and other on* event handlers are removed from elements', () => {
    const html = `<p><a href="https://example.com" onclick="alert('xss')">Click me</a></p><button onmouseover="steal_data()">Hover me</button>`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content.trim().length).toBeGreaterThan(0);
    expect(content).toContain('Click me');
    expect(content).not.toContain('onclick');
    expect(content).not.toContain('onmouseover');
    expect(content).not.toContain('alert(');
    expect(content).not.toContain('steal_data');
  });

  it('xss_script_tag_stripped: Script tag content is stripped and does not appear in output', () => {
    const html = `<p>Safe content.</p><script>alert('xss')</script><p>More safe content.</p>`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content.trim().length).toBeGreaterThan(0);
    expect(content).toContain('Safe content');
    expect(content).toContain('More safe content');
    expect(content).not.toContain('<script>');
    expect(content).not.toContain('alert(');
    expect(content).not.toContain('xss');
  });

  it('xss_svg_nested_script_stripped: Script tags nested inside SVG are stripped', () => {
    const html = `<p>Before SVG.</p><svg xmlns="http://www.w3.org/2000/svg"><script>alert('svg-xss')</script><text>SVG text</text></svg><p>After SVG.</p>`;
    const result = convert(html);
    const content = result.content ?? '';

    expect(content.trim().length).toBeGreaterThan(0);
    expect(content).toContain('Before SVG');
    expect(content).toContain('After SVG');
    expect(content).not.toContain('<script>');
    expect(content).not.toContain('alert(');
    expect(content).not.toContain('svg-xss');
  });

});
